// archive.go
package customers

import (
	"context"
	"net/http"

	"github.com/openmeterio/openmeter/api/v3/apierrors"
	customer "github.com/openmeterio/openmeter/openmeter/customer"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
)

type (
	ArchiveCustomerRequest  = customer.ArchiveCustomerInput
	ArchiveCustomerResponse = interface{}
	ArchiveCustomerParams   = string
	ArchiveCustomerHandler  httptransport.HandlerWithArgs[ArchiveCustomerRequest, ArchiveCustomerResponse, ArchiveCustomerParams]
)

func (h *handler) ArchiveCustomer() ArchiveCustomerHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, customerID ArchiveCustomerParams) (ArchiveCustomerRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return ArchiveCustomerRequest{}, err
			}
			return ArchiveCustomerRequest{Namespace: ns, ID: customerID}, nil
		},
		func(ctx context.Context, request ArchiveCustomerRequest) (ArchiveCustomerResponse, error) {
			return nil, h.service.ArchiveCustomer(ctx, request)
		},
		commonhttp.EmptyResponseEncoder[ArchiveCustomerResponse](http.StatusNoContent),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("archive-customer"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}
